{
  "intent": "check_and_fix",
  "intent_description": "Serial0/1/1 on R2 moved from oper up to lower-layer-down while admin is up; Serial0/1/1 on R3 moved from oper up to down and admin set to down. Impact: point-to-point serial link between R2 and R3 is down causing loss of connectivity. Desired outcome: restore Serial0/1/1 on R2 and R3 to oper up with correct admin state so connectivity is resumed.",
  "target": "R2 and R3 Serial0/1/1",
  "needs_fix": true,
  "plan": {
    "problem": "Point-to-point link Serial0/1/1 between router2 and router3 is down: router2 oper=lower-layer-down admin=up; router3 oper=down admin=down. Connectivity lost.",
    "fix_summary": "Bring interface admin state to up on both endpoints to reinitialize the serial link: (1) issue no shutdown on router2 Serial0/1/1 (restarts line protocol negotiation) and (2) issue no shutdown on router3 Serial0/1/1 (undo admin down). Operational risk: temporary traffic interruption and possible interface flap during re-establishment.",
    "plan_steps": [
      {
        "id": 1,
        "device": "router2",
        "action": "set_interface_admin_state",
        "target": "Serial0/1/1",
        "parameters": [
          "no shutdown"
        ]
      },
      {
        "id": 2,
        "device": "router3",
        "action": "set_interface_admin_state",
        "target": "Serial0/1/1",
        "parameters": [
          "no shutdown"
        ]
      }
    ]
  }
}
